import { createContext, useContext, useState, useCallback } from 'react'
import { useAuth } from './AuthContext'
import API from '../api/axios'

const AiInsightContext = createContext()

export function AiInsightProvider({ children }) {
    const [history, setHistory] = useState([])
    const [quickQuestions, setQuickQuestions] = useState([])
    const [loading, setLoading] = useState(false)
    const { user, token } = useAuth()

    const generateInsight = async (prompt, activeType) => {
        if (!user?.businessId || !token) return { success: false, error: 'Not authenticated' }
        setLoading(true)
        try {
            // Simulated delay for dummy response
            await new Promise(resolve => setTimeout(resolve, 1500))

            let dummyResponse = ''
            if (activeType === 'business_report') {
                dummyResponse = "Based on your recent data, your top performing product is 'Wireless Mouse'. Your overall profit margin has increased by 12% compared to last month. Consider reducing marketing spend on low-performing campaigns to further optimize costs."
            } else if (activeType === 'email') {
                dummyResponse = "Subject: Special 20% Discount Just for You!\n\nHi [Customer Name],\n\nWe noticed you've been a loyal customer of SmartBiz, and we want to thank you! Use code SMART20 at checkout for a 20% discount on your next purchase.\n\nBest regards,\nThe SmartBiz Team"
            } else {
                dummyResponse = "≡ƒÜÇ Exciting news from SmartBiz! We've just restocked our most popular items. Don't miss out on upgrading your workspace today. Shop now at the link in our bio! #Workspace #Tech #SmartBiz"
            }

            return {
                success: true,
                data: {
                    response: dummyResponse
                }
            }
        } catch (error) {
            console.error('Failed to generate insight:', error)
            return { success: false, error: error.response?.data?.message || error.message }
        } finally {
            setLoading(false)
        }
    }

    const fetchHistory = useCallback(async (type = null) => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const endpoint = type
                ? `/business/${user.businessId}/ai-insights/history?type=${type}`
                : `/business/${user.businessId}/ai-insights/history`
            const response = await API.get(endpoint)
            setHistory(response.data)
        } catch (error) {
            console.error('Failed to fetch AI insights history:', error)
        } finally {
            setLoading(false)
        }
    }, [user?.businessId, token])

    const fetchQuickQuestions = useCallback(async (type) => {
        if (!user?.businessId || !token) return
        try {
            const response = await API.get(`/business/${user.businessId}/ai-insights/quick-questions?type=${type}`)
            setQuickQuestions(response.data)
        } catch (error) {
            console.error('Failed to fetch quick questions:', error)
        }
    }, [user?.businessId, token])

    return (
        <AiInsightContext.Provider value={{
            history,
            quickQuestions,
            loading,
            generateInsight,
            fetchHistory,
            fetchQuickQuestions
        }}>
            {children}
        </AiInsightContext.Provider>
    )
}

export const useAiInsight = () => {
    const context = useContext(AiInsightContext)
    if (!context) {
        throw new Error('useAiInsight must be used within an AiInsightProvider')
    }
    return context
}

import { createContext, useContext, useState, useEffect } from 'react'
import API from '../api/axios'

const AuthContext = createContext()

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null)
    const [token, setToken] = useState(localStorage.getItem('token'))
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const savedUser = localStorage.getItem('user')
        if (savedUser && token) {
            setUser(JSON.parse(savedUser))
        }
        setLoading(false)
    }, [token])

    const login = async (email, password) => {
        try {
            const response = await API.post('/auth/login', { email, password })
            const data = response.data

            localStorage.setItem('token', data.token)
            localStorage.setItem('user', JSON.stringify(data))
            setToken(data.token)
            setUser(data)
            return { success: true, data }
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || 'Login failed'
            }
        }
    }

    const register = async (formData) => {
        try {
            const response = await API.post('/auth/register', formData)
            const data = response.data

            localStorage.setItem('token', data.token)
            localStorage.setItem('user', JSON.stringify(data))
            setToken(data.token)
            setUser(data)
            return { success: true, data }
        } catch (error) {
            return {
                success: false,
                message: error.response?.data?.message || 'Registration failed'
            }
        }
    }

    const logout = () => {
        localStorage.removeItem('token')
        localStorage.removeItem('user')
        setToken(null)
        setUser(null)
        window.location.href = '/login'
    }

    return (
        <AuthContext.Provider value={{ user, token, login, register, logout, loading }}>
            {children}
        </AuthContext.Provider>
    )
}

export const useAuth = () => {
    const context = useContext(AuthContext)
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider')
    }
    return context
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { useAuth } from './AuthContext'
import API from '../api/axios'

const CustomerContext = createContext()

export function CustomerProvider({ children }) {
    const [customers, setCustomers] = useState([])
    const [loading, setLoading] = useState(false)
    const { user, token } = useAuth()

    const fetchCustomers = useCallback(async () => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const response = await API.get(`/business/${user.businessId}/customers/getAllCustomers`)
            setCustomers(response.data)
        } catch (error) {
            console.error('Failed to fetch customers:', error)
        } finally {
            setLoading(false)
        }
    }, [user?.businessId, token])

    useEffect(() => {
        if (user?.businessId && token) {
            fetchCustomers()
        } else {
            setCustomers([])
        }
    }, [user?.businessId, token, fetchCustomers])

    const addCustomer = async (customerData) => {
        if (!user?.businessId || !token) return { success: false }
        try {
            const response = await API.post(`/business/${user.businessId}/customers/create`, {
                ...customerData,
                businessId: user.businessId
            })
            if (response.status === 201 || response.status === 200) {
                fetchCustomers()
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const updateCustomer = async (id, updatedData) => {
        if (!user?.businessId || !token) return { success: false }
        try {
            const response = await API.put(`/business/${user.businessId}/customers/${id}`, {
                ...updatedData,
                businessId: user.businessId
            })
            if (response.status === 200) {
                fetchCustomers()
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const deleteCustomer = async (id) => {
        if (!user?.businessId || !token) return { success: false }
        try {
            const response = await API.delete(`/business/${user.businessId}/customers/${id}`)
            if (response.status === 204 || response.status === 200) {
                fetchCustomers()
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    return (
        <CustomerContext.Provider value={{
            customers,
            loading,
            addCustomer,
            updateCustomer,
            deleteCustomer,
            refreshCustomers: fetchCustomers
        }}>
            {children}
        </CustomerContext.Provider>
    )
}

export const useCustomers = () => {
    const context = useContext(CustomerContext)
    if (!context) {
        throw new Error('useCustomers must be used within a CustomerProvider')
    }
    return context
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { useAuth } from './AuthContext'
import API from '../api/axios'

const ProductContext = createContext()

export function ProductProvider({ children }) {
    const [products, setProducts] = useState([])
    const [loading, setLoading] = useState(false)
    const [dashboardStats, setDashboardStats] = useState(null)
    const { user, token } = useAuth()

    const fetchProducts = useCallback(async () => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const response = await API.get(`/business/${user.businessId}/inventory`)
            const data = response.data

            // Map backend fields to frontend fields
            const mappedData = data.map(p => ({
                id: p.productId,
                name: p.productName,
                sku: p.sku,
                category: p.category,
                price: p.price,
                cost: p.cost,
                stock: p.stockLevel,
                minStock: p.minStockLevel
            }))
            setProducts(mappedData)
        } catch (error) {
            console.error('Failed to fetch products:', error)
        } finally {
            setLoading(false)
        }
    }, [user?.businessId, token])

    const fetchDashboardStats = useCallback(async () => {
        if (!user?.businessId || !token) return
        try {
            const response = await API.get(`/business/${user.businessId}/dashboard/kpis`)
            setDashboardStats(response.data)
        } catch (error) {
            console.error('Failed to fetch dashboard stats:', error)
        }
    }, [user?.businessId, token])

    useEffect(() => {
        if (user?.businessId && token) {
            fetchProducts()
            fetchDashboardStats()
        } else {
            setProducts([])
            setDashboardStats(null)
        }
    }, [user?.businessId, token, fetchProducts, fetchDashboardStats])

    const addProduct = async (product) => {
        if (!user?.businessId) return { success: false }
        try {
            const response = await API.post('/business/inventory', {
                productName: product.name,
                sku: product.sku,
                category: product.category,
                price: parseFloat(product.price),
                cost: parseFloat(product.cost),
                stockLevel: parseInt(product.stock),
                minStockLevel: parseInt(product.minStock),
                businessId: user.businessId
            })
            if (response.status === 201 || response.status === 200) {
                fetchProducts()
                fetchDashboardStats()
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const updateProduct = async (id, updatedProduct) => {
        if (!user?.businessId) return { success: false }
        try {
            const response = await API.put(`/business/${user.businessId}/inventory/${id}/edit`, {
                productName: updatedProduct.name,
                sku: updatedProduct.sku,
                category: updatedProduct.category,
                price: parseFloat(updatedProduct.price),
                cost: parseFloat(updatedProduct.cost),
                stockLevel: parseInt(updatedProduct.stock),
                minStockLevel: parseInt(updatedProduct.minStock),
                businessId: user.businessId
            })
            if (response.status === 200) {
                fetchProducts()
                fetchDashboardStats()
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const updateStock = async (productId, currentStock, change) => {
        if (!user?.businessId || !token) return { success: false }
        const newQuantity = currentStock + change
        if (newQuantity < 0) return { success: false, message: 'Stock cannot be negative' }

        try {
            const response = await API.put(`/business/${user.businessId}/inventory/${productId}`, null, {
                params: { quantity: newQuantity }
            })
            if (response.status === 200) {
                // Update local state for fast feedback
                setProducts(prev => prev.map(p =>
                    p.id === productId ? { ...p, stock: newQuantity } : p
                ))
                fetchDashboardStats() // Refresh totals
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            console.error('Failed to update stock:', error)
            return { success: false }
        }
    }

    const deleteProduct = async (id) => {
        if (!user?.businessId) return { success: false }
        try {
            const response = await API.delete(`/business/${user.businessId}/inventory/${id}`)
            if (response.status === 204 || response.status === 200) {
                fetchProducts()
                fetchDashboardStats()
                return { success: true }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const refreshData = useCallback(() => {
        fetchProducts()
        fetchDashboardStats()
    }, [fetchProducts, fetchDashboardStats])

    return (
        <ProductContext.Provider value={{
            products,
            loading,
            dashboardStats,
            addProduct,
            updateProduct,
            updateStock,
            deleteProduct,
            refreshData
        }}>
            {children}
        </ProductContext.Provider>
    )
}

export const useProducts = () => {
    const context = useContext(ProductContext)
    if (!context) {
        throw new Error('useProducts must be used within a ProductProvider')
    }
    return context
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { useAuth } from './AuthContext'
import API from '../api/axios'

const ReportsContext = createContext()

export function ReportsProvider({ children }) {
    const [salesTrend, setSalesTrend] = useState([])
    const [monthlyOverview, setMonthlyOverview] = useState({})
    const [topProducts, setTopProducts] = useState([])
    const [expensesByCategory, setExpensesByCategory] = useState([])
    const [lowStockAlerts, setLowStockAlerts] = useState([])
    const [loading, setLoading] = useState(false)
    const { user, token } = useAuth()

    const fetchReports = useCallback(async () => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const [
                salesRes,
                monthlyRes,
                topRes,
                expensesRes,
                lowStockRes
            ] = await Promise.all([
                API.get(`/business/${user.businessId}/reports/sales-trend`),
                API.get(`/business/${user.businessId}/reports/monthly-overview`),
                API.get(`/business/${user.businessId}/reports/top-products`),
                API.get(`/business/${user.businessId}/reports/expenses-by-category`),
                API.get(`/business/${user.businessId}/reports/low-stock-alerts`)
            ])

            setSalesTrend(salesRes.data)
            setMonthlyOverview(monthlyRes.data)
            setTopProducts(topRes.data)
            setExpensesByCategory(expensesRes.data)
            setLowStockAlerts(lowStockRes.data)
        } catch (error) {
            console.error('Failed to fetch reports:', error)
        } finally {
            setLoading(false)
        }
    }, [user?.businessId, token])

    useEffect(() => {
        if (user?.businessId && token) {
            fetchReports()
        } else {
            setSalesTrend([])
            setMonthlyOverview({})
            setTopProducts([])
            setExpensesByCategory([])
            setLowStockAlerts([])
        }
    }, [user?.businessId, token, fetchReports])

    return (
        <ReportsContext.Provider value={{
            salesTrend,
            monthlyOverview,
            topProducts,
            expensesByCategory,
            lowStockAlerts,
            loading,
            fetchReports
        }}>
            {children}
        </ReportsContext.Provider>
    )
}

export const useReports = () => {
    const context = useContext(ReportsContext)
    if (!context) {
        throw new Error('useReports must be used within a ReportsProvider')
    }
    return context
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { useAuth } from './AuthContext'
import API from '../api/axios'

const SalesContext = createContext()

export function SalesProvider({ children }) {
    const [sales, setSales] = useState([])
    const [loading, setLoading] = useState(false)
    const { user, token } = useAuth()

    const fetchSales = useCallback(async () => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const response = await API.get(`/business/${user.businessId}/sales`)
            setSales(response.data)
        } catch (error) {
            console.error('Failed to fetch sales:', error)
        } finally {
            setLoading(false)
        }
    }, [user?.businessId, token])

    useEffect(() => {
        if (user?.businessId && token) {
            fetchSales()
        } else {
            setSales([])
        }
    }, [user?.businessId, token, fetchSales])

    const searchSales = async (query) => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const response = await API.get(`/business/${user.businessId}/sales/search`, {
                params: { q: query }
            })
            setSales(response.data)
        } catch (error) {
            console.error('Failed to search sales:', error)
        } finally {
            setLoading(false)
        }
    }

    const getSaleDetails = async (saleId) => {
        if (!user?.businessId || !token) return null
        try {
            const response = await API.get(`/business/${user.businessId}/sales/${saleId}`)
            return response.data
        } catch (error) {
            console.error('Failed to fetch sale details:', error)
            return null
        }
    }

    const recordSale = async (saleData) => {
        if (!user?.businessId || !token) return { success: false }
        try {
            const response = await API.post(`/mobile/${user.businessId}/sales`, {
                ...saleData
            })
            if (response.status === 201 || response.status === 200) {
                fetchSales()
                return { success: true, data: response.data }
            }
            return { success: false }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const deleteSale = async (saleId) => {
        if (!user?.businessId || !token) return { success: false }
        try {
            await API.delete(`/business/${user.businessId}/sales/${saleId}`)
            fetchSales() // Refresh the list
            return { success: true }
        } catch (error) {
            console.error('Failed to delete sale:', error)
            return { success: false, error: error.message }
        }
    }

    return (
        <SalesContext.Provider value={{
            sales,
            loading,
            fetchSales,
            searchSales,
            getSaleDetails,
            recordSale,
            deleteSale
        }}>
            {children}
        </SalesContext.Provider>
    )
}

export const useSales = () => {
    const context = useContext(SalesContext)
    if (!context) {
        throw new Error('useSales must be used within a SalesProvider')
    }
    return context
}

