import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { useAuth } from './AuthContext'
import API from '../api/axios'

const TransactionContext = createContext()

export function TransactionProvider({ children }) {
    const [transactions, setTransactions] = useState([])
    const [loading, setLoading] = useState(false)
    const { user, token } = useAuth()

    const fetchTransactions = useCallback(async () => {
        if (!user?.businessId || !token) return
        setLoading(true)
        try {
            const response = await API.get(`/business/${user.businessId}/transactions/getAll`)
            setTransactions(response.data)
        } catch (error) {
            console.error('Failed to fetch transactions:', error)
        } finally {
            setLoading(false)
        }
    }, [user?.businessId, token])

    useEffect(() => {
        if (user?.businessId && token) {
            fetchTransactions()
        } else {
            setTransactions([])
        }
    }, [user?.businessId, token, fetchTransactions])

    const addTransaction = async (data) => {
        if (!user?.businessId || !token) return { success: false, error: 'Not authenticated' }
        try {
            const payload = { ...data, businessId: user.businessId }
            const response = await API.post(`/business/${user.businessId}/transactions/addTransaction`, payload)
            if (response.status === 201 || response.status === 200) {
                fetchTransactions()
                return { success: true, data: response.data }
            }
            return { success: false, error: 'Failed to record transaction' }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const editTransaction = async (id, data) => {
        if (!user?.businessId || !token) return { success: false, error: 'Not authenticated' }
        try {
            const payload = { ...data, businessId: user.businessId }
            const response = await API.put(`/business/${user.businessId}/transactions/${id}`, payload)
            if (response.status === 200) {
                fetchTransactions()
                return { success: true, data: response.data }
            }
            return { success: false, error: 'Failed to update transaction' }
        } catch (error) {
            return { success: false, error: error.message }
        }
    }

    const deleteTransaction = async (id) => {
        if (!user?.businessId || !token) return { success: false, error: 'Not authenticated' }
        try {
            await API.delete(`/business/${user.businessId}/transactions/${id}`)
            fetchTransactions() // Refresh the list
            return { success: true }
        } catch (error) {
            console.error('Failed to delete transaction:', error)
            return { success: false, error: error.message }
        }
    }

    return (
        <TransactionContext.Provider value={{
            transactions,
            loading,
            fetchTransactions,
            addTransaction,
            editTransaction,
            deleteTransaction
        }}>
            {children}
        </TransactionContext.Provider>
    )
}

export const useTransactions = () => {
    const context = useContext(TransactionContext)
    if (!context) {
        throw new Error('useTransactions must be used within a TransactionProvider')
    }
    return context
}

import { useState, useEffect } from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import Button from '../../../common/component/Button/Button'
import MuiTextField from '@mui/material/TextField'
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome'
import SendIcon from '@mui/icons-material/Send'
import { useAiInsight } from '../../../context/AiInsightContext'
import './BusinessOwnerAiInsight.css'

export default function BusinessOwnerAiInsight() {
    const { generateInsight, loading } = useAiInsight()

    const [activeTab, setActiveTab] = useState('business_report')
    const [prompt, setPrompt] = useState('')
    const [response, setResponse] = useState(null)
    const [error, setError] = useState(null)

    const tabs = [
        { id: 'business_report', label: 'Business Reports' },
        { id: 'email', label: 'Email Generator' },
        { id: 'marketing', label: 'Marketing Posts' }
    ]

    const quickQuestions = {
        'business_report': ['Top Products', 'Profit Analysis', 'Stock Status'],
        'email': ['Follow-up Email', 'Welcome Email', 'Discount Offer'],
        'marketing': ['Facebook Post', 'Instagram Captions', 'Holiday Promo']
    }

    // Clear response when switching tabs
    useEffect(() => {
        setResponse(null)
        setError(null)
        setPrompt('')
    }, [activeTab])

    const handleGenerate = async (queryOverride = null) => {
        const query = typeof queryOverride === 'string' ? queryOverride : prompt
        if (!query.trim()) return

        setError(null)
        setResponse(null)
        setPrompt(query)

        const result = await generateInsight(query, activeTab)
        if (result.success) {
            setResponse(result.data.response)
        } else {
            setError(result.error)
        }
    }

    return (
        <OwnerLayout breadcrumb="AI-Insight">
            <div className="ai-insight-page">
                <div className="ai-card">
                    <div className="ai-card-header" style={{ justifyContent: 'space-between', marginBottom: '24px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <AutoAwesomeIcon sx={{ color: '#8A2BE2', fontSize: 24 }} />
                            <h2 className="ai-title">AI Insights</h2>
                        </div>
                        <div className="status-badge" style={{ backgroundColor: '#fff3cd', color: '#856404', padding: '6px 12px', borderRadius: '4px', fontSize: '12px', fontWeight: 'bold' }}>
                            Demo Mode (Disabled)
                        </div>
                    </div>

                    <div className="ai-tabs">
                        {tabs.map((tab) => (
                            <button
                                key={tab.id}
                                className={`ai-tab ${activeTab === tab.id ? 'ai-tab--active' : ''}`}
                                onClick={() => setActiveTab(tab.id)}
                            >
                                {tab.label}
                            </button>
                        ))}
                    </div>

                    <div className="ai-form-section">
                        <h3 className="ai-section-title">Ask a question about your business</h3>
                        <div className="ai-input-group">
                            <MuiTextField
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                placeholder="e.g., How did I perform last month?"
                                variant="outlined"
                                fullWidth
                                multiline
                                rows={2}
                                sx={{
                                    '& .MuiOutlinedInput-root': {
                                        borderRadius: '8px',
                                        backgroundColor: '#F3F4F6'
                                    }
                                }}
                            />
                        </div>

                        <Button
                            variant="filled"
                            fullWidth
                            startIcon={<SendIcon sx={{ transform: 'rotate(-45deg)', mt: '-2px' }} />}
                            onClick={() => handleGenerate()}
                            disabled={loading || !prompt.trim()}
                            sx={{
                                backgroundColor: '#0B0F19',
                                color: '#FFF',
                                borderRadius: '8px',
                                padding: '12px',
                                mt: 2,
                                textTransform: 'none',
                                fontSize: '15px'
                            }}
                        >
                            {loading ? 'Generating...' : 'Generate AI Report'}
                        </Button>
                    </div>

                    <div className="ai-quick-questions">
                        <h4 className="quick-questions-title">Quick Questions</h4>
                        <div className="quick-chips">
                            {quickQuestions[activeTab]?.map((q, idx) => (
                                <button
                                    key={idx}
                                    className="quick-chip"
                                    onClick={() => handleGenerate(q)}
                                >
                                    {q}
                                </button>
                            ))}
                        </div>
                    </div>

                    {(response || error) && (
                        <div className={`ai-response-container ${error ? 'ai-response-error' : ''}`}>
                            <h4 className="response-title">{error ? 'Error Generating Insight' : 'AI Response'}</h4>
                            <div className="response-content">
                                {error ? error : response?.split('\n').map((line, i) => <p key={i}>{line}</p>)}
                            </div>
                        </div>
                    )}

                </div>
            </div>
        </OwnerLayout >
    )
}

import { useState, useMemo } from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import DataTable from '../../../common/component/DataTable/DataTable'
import TextField from '../../../common/component/TextField/TextField'
import Button from '../../../common/component/Button/Button'
import Modal from '../../../common/component/Modal/Modal'
import SearchIcon from '@mui/icons-material/Search'
import AddIcon from '@mui/icons-material/Add'
import EditOutlinedIcon from '@mui/icons-material/EditOutlined'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'
import EmailOutlinedIcon from '@mui/icons-material/EmailOutlined'
import PhoneOutlinedIcon from '@mui/icons-material/PhoneOutlined'
import { useCustomers } from '../../../context/CustomerContext'
import './BusinessOwnerCustomers.css'

export default function BusinessOwnerCustomers() {
    const { customers, loading, addCustomer, updateCustomer, deleteCustomer } = useCustomers()
    const [searchQuery, setSearchQuery] = useState('')
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [editingCustomer, setEditingCustomer] = useState(null)
    const [isSubmitting, setIsSubmitting] = useState(false)

    // Form State
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        phone: '',
        address: ''
    })

    const filteredCustomers = useMemo(() => {
        return customers.filter(c =>
            c.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            c.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            c.phone?.includes(searchQuery)
        )
    }, [customers, searchQuery])

    const handleInputChange = (e) => {
        const { name, value } = e.target
        setFormData(prev => ({ ...prev, [name]: value }))
    }

    const handleOpenAddModal = () => {
        setEditingCustomer(null)
        setFormData({ name: '', email: '', phone: '', address: '' })
        setIsModalOpen(true)
    }

    const handleOpenEditModal = (customer) => {
        setEditingCustomer(customer)
        setFormData({
            name: customer.name || '',
            email: customer.email || '',
            phone: customer.phone || '',
            address: customer.address || ''
        })
        setIsModalOpen(true)
    }

    const handleDeleteCustomer = async (id) => {
        if (window.confirm('Are you sure you want to delete this customer?')) {
            await deleteCustomer(id)
        }
    }

    const handleSubmit = async (e) => {
        e.preventDefault()
        setIsSubmitting(true)

        let result;
        if (editingCustomer) {
            result = await updateCustomer(editingCustomer.customerId, formData)
        } else {
            result = await addCustomer(formData)
        }

        if (result.success) {
            setIsModalOpen(false)
        } else {
            alert('Failed to save customer. Please try again.')
        }
        setIsSubmitting(false)
    }

    const columns = useMemo(() => [
        {
            key: 'name',
            label: 'Name',
            render: (val) => <span style={{ fontWeight: 600 }}>{val}</span>
        },
        {
            key: 'contact',
            label: 'Contact',
            render: (_, row) => (
                <div className="contact-cell">
                    <div className="contact-item">
                        <EmailOutlinedIcon /> {row.email}
                    </div>
                    <div className="contact-item">
                        <PhoneOutlinedIcon /> {row.phone}
                    </div>
                </div>
            )
        },
        {
            key: 'address',
            label: 'Address',
            render: (val) => <div className="address-cell">{val}</div>
        },
        {
            key: 'totalPurchases',
            label: 'Total Purchases',
            render: (val) => <span className="purchases-cell">${Number(val || 0).toFixed(2)}</span>
        },
        {
            key: 'actions',
            label: 'Actions',
            render: (_, row) => (
                <div className="action-buttons">
                    <button
                        className="action-btn action-btn--edit"
                        onClick={() => handleOpenEditModal(row)}
                    >
                        <EditOutlinedIcon />
                    </button>
                    <button
                        className="action-btn action-btn--delete"
                        onClick={() => handleDeleteCustomer(row.customerId)}
                    >
                        <DeleteOutlineIcon />
                    </button>
                </div>
            )
        }
    ], [])

    return (
        <OwnerLayout breadcrumb="Customers">
            <div className="customers-page">
                <div className="customers-section">
                    <div className="customers-header">
                        <h2 className="customers-title">Customer Management</h2>
                        <Button
                            variant="filled"
                            startIcon={<AddIcon />}
                            onClick={handleOpenAddModal}
                            sx={{ backgroundColor: '#000', borderRadius: '8px' }}
                        >
                            Add Customer
                        </Button>
                    </div>

                    <div className="customers-toolbar">
                        <TextField
                            placeholder="Search customers..."
                            icon={<SearchIcon />}
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            fullWidth
                        />
                    </div>

                    <div className="customers-table-container">
                        <DataTable
                            columns={columns}
                            data={filteredCustomers}
                            isLoading={loading && customers.length === 0}
                        />
                    </div>
                </div>
            </div>

            {/* Add/Edit Customer Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingCustomer ? "Edit Customer" : "Add New Customer"}
            >
                <form className="customer-form" onSubmit={handleSubmit}>
                    <div className="form-grid">
                        <TextField
                            name="name"
                            label="Customer Name"
                            placeholder="Enter Customer Name"
                            value={formData.name}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                        <TextField
                            name="email"
                            label="Email Address"
                            type="email"
                            placeholder="Enter Email Address"
                            value={formData.email}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                        <TextField
                            name="phone"
                            label="Phone Number"
                            placeholder="Enter Phone Number"
                            value={formData.phone}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                        <TextField
                            name="address"
                            label="Address"
                            placeholder="Enter Address"
                            value={formData.address}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                    </div>
                    <div className="form-actions">
                        <Button variant="outlined" onClick={() => setIsModalOpen(false)} disabled={isSubmitting}>
                            Cancel
                        </Button>
                        <Button type="submit" variant="filled" disabled={isSubmitting}>
                            {isSubmitting ? 'Saving...' : (editingCustomer ? 'Update Customer' : 'Add Customer')}
                        </Button>
                    </div>
                </form>
            </Modal>
        </OwnerLayout>
    )
}

import { useState, useMemo } from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import DataTable from '../../../common/component/DataTable/DataTable'
import TextField from '../../../common/component/TextField/TextField'
import Button from '../../../common/component/Button/Button'
import Modal from '../../../common/component/Modal/Modal'
import SearchIcon from '@mui/icons-material/Search'
import AddIcon from '@mui/icons-material/Add'
import EditOutlinedIcon from '@mui/icons-material/EditOutlined'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'
import { useProducts } from '../../../context/ProductContext'
import './OwnerProductsPage.css'

export default function OwnerProductsPage() {
    const { products, loading, addProduct, updateProduct, deleteProduct } = useProducts()
    const [searchQuery, setSearchQuery] = useState('')
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [editingProduct, setEditingProduct] = useState(null)
    const [isSubmitting, setIsSubmitting] = useState(false)

    // Form State
    const [formData, setFormData] = useState({
        name: '',
        sku: '',
        category: '',
        price: '',
        cost: '',
        stock: '',
        minStock: ''
    })

    const filteredProducts = products.filter(p =>
        (p.name?.toLowerCase().includes(searchQuery.toLowerCase())) ||
        (p.sku?.toLowerCase().includes(searchQuery.toLowerCase()))
    )

    // Handlers
    const handleInputChange = (e) => {
        const { name, value } = e.target
        setFormData(prev => ({ ...prev, [name]: value }))
    }

    const handleOpenAddModal = () => {
        setEditingProduct(null)
        setFormData({ name: '', sku: '', category: '', price: '', cost: '', stock: '', minStock: '' })
        setIsModalOpen(true)
    }

    const handleOpenEditModal = (product) => {
        setEditingProduct(product)
        setFormData({
            ...product,
            price: product.price?.toString() || '',
            cost: product.cost?.toString() || '',
            stock: product.stock?.toString() || '',
            minStock: product.minStock?.toString() || ''
        })
        setIsModalOpen(true)
    }

    const handleDeleteProduct = async (id) => {
        if (window.confirm('Are you sure you want to delete this product?')) {
            await deleteProduct(id)
        }
    }

    const handleSubmit = async (e) => {
        e.preventDefault()
        setIsSubmitting(true)

        const processedData = {
            ...formData,
            price: parseFloat(formData.price) || 0,
            cost: parseFloat(formData.cost) || 0,
            stock: parseInt(formData.stock) || 0,
            minStock: parseInt(formData.minStock) || 0
        }

        let result;
        if (editingProduct) {
            result = await updateProduct(editingProduct.id, processedData)
        } else {
            result = await addProduct(processedData)
        }

        if (result.success) {
            setIsModalOpen(false)
        } else {
            alert('Failed to save product. Please try again.')
        }
        setIsSubmitting(false)
    }

    // Column Definitions moved inside component to access handlers
    const productColumns = useMemo(() => [
        { key: 'name', label: 'Name' },
        { key: 'sku', label: 'SKU' },
        { key: 'category', label: 'Category' },
        { key: 'price', label: 'Price', render: (val) => `$${Number(val || 0).toFixed(2)}` },
        { key: 'cost', label: 'Cost', render: (val) => `$${Number(val || 0).toFixed(2)}` },
        { key: 'stock', label: 'Stock' },
        { key: 'minStock', label: 'Min Stock' },
        {
            key: 'action', label: 'Action', render: (_, row) => (
                <div className="action-buttons">
                    <button
                        className="action-btn action-btn--edit"
                        title="Edit"
                        onClick={() => handleOpenEditModal(row)}
                    >
                        <EditOutlinedIcon />
                    </button>
                    <button
                        className="action-btn action-btn--delete"
                        title="Delete"
                        onClick={() => handleDeleteProduct(row.id)}
                    >
                        <DeleteOutlineIcon />
                    </button>
                </div>
            )
        }
    ], [products])

    return (
        <OwnerLayout breadcrumb="Products">
            <div className="owner-products-inner-content">
                <div className="content-toolbar">
                    <h1 className="content-title">Product And Inventory</h1>
                    <Button
                        type="primary"
                        startIcon={<AddIcon />}
                        className="add-product-btn"
                        onClick={handleOpenAddModal}
                    >
                        Add Product
                    </Button>
                </div>

                <div className="search-bar-container">
                    <TextField
                        placeholder="Search Product"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        icon={<SearchIcon />}
                        fullWidth
                        className="product-search-field"
                    />
                </div>

                <div className="table-container">
                    {loading && products.length === 0 ? (
                        <div style={{ padding: '20px', textAlign: 'center' }}>Loading products...</div>
                    ) : (
                        <DataTable columns={productColumns} data={filteredProducts} />
                    )}
                </div>
            </div>

            {/* Product Modal (Add/Edit) */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingProduct ? "Edit Product" : "Add New Product"}
            >
                <form className="add-product-form" onSubmit={handleSubmit}>
                    <div className="form-grid">
                        <TextField
                            name="name"
                            placeholder="Enter Product Name"
                            label="Name"
                            value={formData.name}
                            onChange={handleInputChange}
                            required
                        />
                        <TextField
                            name="sku"
                            placeholder="Enter SKU Code"
                            label="SKU"
                            value={formData.sku}
                            onChange={handleInputChange}
                            required
                        />
                        <TextField
                            name="category"
                            placeholder="Enter Category"
                            label="Category"
                            value={formData.category}
                            onChange={handleInputChange}
                            required
                        />
                        <TextField
                            name="price"
                            type="number"
                            placeholder="Enter Selling Price"
                            label="Price"
                            value={formData.price}
                            onChange={handleInputChange}
                            required
                        />
                        <TextField
                            name="cost"
                            type="number"
                            placeholder="Enter Cost Price"
                            label="Cost"
                            value={formData.cost}
                            onChange={handleInputChange}
                            required
                        />
                        <TextField
                            name="stock"
                            type="number"
                            placeholder="Enter Initial Stock"
                            label="Stock"
                            value={formData.stock}
                            onChange={handleInputChange}
                            required
                        />
                        <TextField
                            name="minStock"
                            type="number"
                            placeholder="Enter Min Stock Level"
                            label="Min Stock"
                            value={formData.minStock}
                            onChange={handleInputChange}
                            required
                        />
                    </div>
                    <div className="form-actions">
                        <Button variant="outlined" onClick={() => setIsModalOpen(false)} disabled={isSubmitting}>Cancel</Button>
                        <Button type="submit" variant="filled" disabled={isSubmitting}>
                            {isSubmitting ? 'Saving...' : (editingProduct ? "Update Product" : "Save Product")}
                        </Button>
                    </div>
                </form>
            </Modal>
        </OwnerLayout>
    )
}

import React from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import {
    LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    BarChart, Bar, Legend, PieChart, Pie, Cell, Tooltip as PieTooltip
} from 'recharts'
import { useReports } from '../../../context/ReportsContext'
import './BusinessOwnerReports.css'

export default function BusinessOwnerReports() {
    const {
        salesTrend,
        monthlyOverview,
        topProducts,
        expensesByCategory,
        lowStockAlerts,
        loading
    } = useReports()

    const COLORS = ['#4285F4', '#34A853', '#FBBC05', '#EA4335', '#8A2BE2', '#FF69B4', '#00CED1']

    // Format Monthly Overview data for BarChart
    const monthlyData = [
        { name: 'Revenue', value: monthlyOverview?.revenue || 0 },
        { name: 'Expenses', value: monthlyOverview?.expenses || 0 },
        { name: 'Profit', value: monthlyOverview?.profit || 0 }
    ]

    const formatCurrency = (value) => {
        return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value)
    }

    if (loading) {
        return (
            <OwnerLayout breadcrumb="Reports">
                <div className="reports-page loading-state">
                    Loading reports...
                </div>
            </OwnerLayout>
        )
    }

    return (
        <OwnerLayout breadcrumb="Reports">
            <div className="reports-page">
                <div className="reports-grid">

                    {/* Sales Trend */}
                    <div className="report-card">
                        <h3 className="report-title">Sales Trend (Last 30 Days)</h3>
                        <div className="chart-container">
                            <ResponsiveContainer width="100%" height="100%">
                                <LineChart data={salesTrend}>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                    <XAxis
                                        dataKey="date"
                                        axisLine={false}
                                        tickLine={false}
                                        tickFormatter={(val) => {
                                            const d = new Date(val)
                                            return `${d.toLocaleString('default', { month: 'short' })} ${d.getDate()}`
                                        }}
                                        tick={{ fill: '#718096', fontSize: 12 }}
                                    />
                                    <YAxis
                                        axisLine={false}
                                        tickLine={false}
                                        tick={{ fill: '#718096', fontSize: 12 }}
                                        tickFormatter={(val) => `$${val}`}
                                    />
                                    <Tooltip
                                        formatter={(value) => [formatCurrency(value), 'Amount']}
                                        labelFormatter={(label) => new Date(label).toDateString()}
                                    />
                                    <Line type="monotone" dataKey="amount" stroke="#4285F4" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                                </LineChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Monthly Overview */}
                    <div className="report-card">
                        <h3 className="report-title">Monthly Overview</h3>
                        <div className="chart-container">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={monthlyData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#718096', fontSize: 12 }} />
                                    <YAxis axisLine={false} tickLine={false} tick={{ fill: '#718096', fontSize: 12 }} tickFormatter={(val) => `$${val}`} />
                                    <Tooltip formatter={(value) => formatCurrency(value)} cursor={{ fill: '#F7FAFC' }} />
                                    <Bar dataKey="value" fill="#4285F4" radius={[4, 4, 0, 0]}>
                                        {monthlyData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.name === 'Experiences' ? '#EA4335' : entry.name === 'Profit' ? '#34A853' : '#4285F4'} />
                                        ))}
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Top Selling Products */}
                    <div className="report-card">
                        <h3 className="report-title">Top Selling Products</h3>
                        <div className="chart-container">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={topProducts} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#E2E8F0" />
                                    <XAxis type="number" axisLine={false} tickLine={false} tick={{ fill: '#718096', fontSize: 12 }} />
                                    <YAxis type="category" dataKey="productName" axisLine={false} tickLine={false} tick={{ fill: '#718096', fontSize: 12 }} width={100} />
                                    <Tooltip cursor={{ fill: '#F7FAFC' }} />
                                    <Bar dataKey="totalQty" fill="#10B981" radius={[0, 4, 4, 0]} barSize={30} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Expenses by Category */}
                    <div className="report-card">
                        <h3 className="report-title">Expenses by Category</h3>
                        <div className="chart-container flex-center">
                            {expensesByCategory.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={expensesByCategory}
                                            dataKey="amount"
                                            nameKey="category"
                                            cx="50%"
                                            cy="50%"
                                            outerRadius={100}
                                            innerRadius={0}
                                            fill="#8884d8"
                                            label={({ cx, cy, midAngle, innerRadius, outerRadius, value, index }) => {
                                                const RADIAN = Math.PI / 180;
                                                const radius = outerRadius * 1.35;
                                                const x = cx + radius * Math.cos(-midAngle * RADIAN);
                                                const y = cy + radius * Math.sin(-midAngle * RADIAN);
                                                return (
                                                    <text x={x} y={y} fill={COLORS[index % COLORS.length]} textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" fontSize="12" fontWeight="600">
                                                        {`${expensesByCategory[index].category} ${((value / expensesByCategory.reduce((a, b) => a + Number(b.amount), 0)) * 100).toFixed(0)}%`}
                                                    </text>
                                                )
                                            }}
                                            labelLine={false}
                                        >
                                            {expensesByCategory.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                            ))}
                                        </Pie>
                                        <PieTooltip formatter={(value) => formatCurrency(value)} />
                                    </PieChart>
                                </ResponsiveContainer>
                            ) : (
                                <p className="no-data">No expense data available</p>
                            )}
                        </div>
                    </div>

                </div>

                {/* Low Stock Alert */}
                <div className="report-card full-width mt-6">
                    <h3 className="report-title">Low Stock Alert</h3>
                    <div className="alerts-container">
                        {lowStockAlerts.length > 0 ? (
                            lowStockAlerts.map((alert, index) => (
                                <div className="alert-item" key={index}>
                                    <div className="alert-details">
                                        <h4>{alert.productName}</h4>
                                        <p>SKU: {alert.sku}</p>
                                    </div>
                                    <div className="alert-stats">
                                        <span className="stock-level">{alert.stockLevel} units</span>
                                        <span className="min-level">Min: {alert.minStockLevel}</span>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <p className="no-data">All products are sufficiently stocked.</p>
                        )}
                    </div>
                </div>

            </div>
        </OwnerLayout>
    )
}

import { useState, useMemo, useEffect } from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import DataTable from '../../../common/component/DataTable/DataTable'
import TextField from '../../../common/component/TextField/TextField'
import Button from '../../../common/component/Button/Button'
import Modal from '../../../common/component/Modal/Modal'
import SearchIcon from '@mui/icons-material/Search'
import AddIcon from '@mui/icons-material/Add'
import ReceiptLongOutlinedIcon from '@mui/icons-material/ReceiptLongOutlined'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'
import InvoiceModal from '../../../common/component/InvoiceModal/InvoiceModal'
import Autocomplete from '@mui/material/Autocomplete'
import MuiTextField from '@mui/material/TextField'
import MenuItem from '@mui/material/MenuItem'
import Select from '@mui/material/Select'
import FormControl from '@mui/material/FormControl'
import InputLabel from '@mui/material/InputLabel'
import { useSales } from '../../../context/SalesContext'
import { useProducts } from '../../../context/ProductContext'
import { useCustomers } from '../../../context/CustomerContext'
import { useAuth } from '../../../context/AuthContext'
import './BusinessOwnerSales.css'

export default function BusinessOwnerSales() {
    const { user } = useAuth()
    const { sales, loading, searchSales, recordSale, getSaleDetails, deleteSale } = useSales()
    const { products, refreshData: refreshProducts } = useProducts()
    const { customers, refreshCustomers } = useCustomers()

    useEffect(() => {
        refreshProducts()
        refreshCustomers()
    }, [refreshProducts, refreshCustomers])

    const [searchQuery, setSearchQuery] = useState('')
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [isInvoiceModalOpen, setIsInvoiceModalOpen] = useState(false)
    const [selectedSale, setSelectedSale] = useState(null)
    const [isSubmitting, setIsSubmitting] = useState(false)

    // New Sale Form State
    const [selectedCustomer, setSelectedCustomer] = useState(null)
    const [cart, setCart] = useState([])
    const [paymentMethod, setPaymentMethod] = useState('cash')

    const handleSearch = (e) => {
        const query = e.target.value
        setSearchQuery(query)
        searchSales(query)
    }

    const handleViewInvoice = async (sale) => {
        if (!sale) return
        const sid = sale.saleId || sale.id
        if (!sid) {
            alert('Invalid sale ID')
            return
        }

        try {
            const details = await getSaleDetails(sid)
            if (details) {
                setSelectedSale(details)
                setIsInvoiceModalOpen(true)
            } else {
                alert('Invoice details not found.')
            }
        } catch (error) {
            alert('Failed to load invoice: ' + error.message)
        }
    }

    const handleDeleteSale = async (sale) => {
        if (!sale) return
        const sid = sale.saleId || sale.id
        if (window.confirm('Are you sure you want to delete this sale? Product stock levels will be restored automatically.')) {
            try {
                const res = await deleteSale(sid)
                if (!res.success) {
                    alert('Error: ' + (res.error || 'Failed to delete sale'))
                }
            } catch (err) {
                alert('An unexpected error occurred.')
            }
        }
    }

    const addToCart = (product) => {
        if (!product) return
        setCart(prev => {
            const existing = prev.find(item => item.id === product.id)
            if (existing) {
                return prev.map(item =>
                    item.id === product.id ? { ...item, qty: item.qty + 1 } : item
                )
            }
            return [...prev, { ...product, qty: 1 }]
        })
    }

    const removeFromCart = (productId) => {
        setCart(prev => prev.filter(item => item.id !== productId))
    }

    const updateCartQty = (productId, qty) => {
        if (qty < 1) return
        setCart(prev => prev.map(item =>
            item.id === productId ? { ...item, qty } : item
        ))
    }

    const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.qty), 0)

    const handleCreateSale = async () => {
        if (cart.length === 0) return

        // Final validation to prevent "Null ID" backend error
        const invalidItems = cart.filter(item => !item.id)
        if (invalidItems.length > 0) {
            alert('One or more items are invalid. Please re-add them.')
            console.error('Missing ID for items:', invalidItems)
            return
        }

        setIsSubmitting(true)

        const saleData = {
            customerId: selectedCustomer?.customerId,
            customerName: selectedCustomer ? selectedCustomer.name : 'Walk-in Customer',
            customerEmail: selectedCustomer?.email,
            customerPhone: selectedCustomer?.phone,
            items: cart.map(item => ({
                productId: item.id,
                qty: item.qty,
                price: item.price
            })),
            totalAmount: totalAmount,
            itemsCount: cart.reduce((sum, i) => sum + i.qty, 0),
            paymentMethod: paymentMethod,
            status: 'completed'
        }

        console.log('Recording sale with payload:', saleData)
        const result = await recordSale(saleData)

        if (result.success) {
            setIsModalOpen(false)
            setCart([])
            setSelectedCustomer(null)
            setPaymentMethod('cash')

            // Just notify or refresh, don't auto-open invoice based on new request
            console.log('Sale recorded successfully')
        } else {
            console.error('Sale recording failed:', result.error)
            alert('Failed to record sale: ' + (result.error || 'Unknown error'))
        }
        setIsSubmitting(false)
    }

    const columns = useMemo(() => [
        {
            key: 'invoiceNumber',
            label: 'Invoice #',
            render: (val) => <span className="invoice-cell">{val || 'N/A'}</span>
        },
        {
            key: 'customerName',
            label: 'Customer',
            render: (val) => <span className="customer-cell">{val || 'Walk-in Customer'}</span>
        },
        {
            key: 'itemsCount',
            label: 'Items',
            render: (val) => <span>{val || 0} item(s)</span>
        },
        {
            key: 'totalAmount',
            label: 'Total',
            render: (val) => <span className="total-cell">${Number(val || 0).toFixed(2)}</span>
        },
        {
            key: 'paymentMethod',
            label: 'Payment',
            render: (val) => <span className="payment-cell">{val || 'Cash'}</span>
        },
        {
            key: 'status',
            label: 'Status',
            render: (val) => (
                <span className={`status-badge status-badge--${(val || 'completed').toLowerCase()}`}>
                    {val || 'Completed'}
                </span>
            )
        },
        {
            key: 'saleDate',
            label: 'Date',
            render: (val) => <span>{val ? new Date(val).toLocaleDateString() : 'N/A'}</span>
        },
        {
            key: 'actions',
            label: 'Actions',
            render: (_, row) => (
                <div className="action-buttons">
                    <button
                        className="action-btn action-btn--view"
                        title="View Invoice"
                        onClick={() => handleViewInvoice(row)}
                    >
                        <ReceiptLongOutlinedIcon sx={{ fontSize: 20 }} />
                    </button>
                    <button
                        className="action-btn action-btn--delete"
                        title="Delete Sale"
                        onClick={() => handleDeleteSale(row)}
                        style={{ color: '#e53e3e', marginLeft: '8px' }}
                    >
                        <DeleteOutlineIcon sx={{ fontSize: 20 }} />
                    </button>
                </div>
            )
        }
    ], [])

    return (
        <OwnerLayout breadcrumb="Sales">
            <div className="sales-page">
                <div className="sales-section">
                    <div className="sales-header">
                        <h2 className="sales-title">Sales & Invoices</h2>
                        <Button
                            variant="filled"
                            startIcon={<AddIcon />}
                            onClick={() => setIsModalOpen(true)}
                            sx={{ backgroundColor: '#000', borderRadius: '8px' }}
                        >
                            New Sale
                        </Button>
                    </div>

                    <div className="sales-toolbar">
                        <TextField
                            placeholder="Search sales history..."
                            icon={<SearchIcon />}
                            value={searchQuery}
                            onChange={handleSearch}
                            fullWidth
                        />
                    </div>

                    <div className="sales-table-container">
                        <DataTable
                            columns={columns}
                            data={sales}
                            isLoading={loading && sales.length === 0}
                        />
                    </div>
                </div>
            </div>

            {/* New Sale Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title="Create New Sale"
            >
                <div className="new-sale-container">
                    <div className="new-sale-grid">
                        <div className="new-sale-form">
                            <div className="form-group">
                                <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Search Customer (Optional)</InputLabel>
                                <Autocomplete
                                    options={customers || []}
                                    getOptionLabel={(option) => option?.name ? `${option.name} (${option.phone || 'No phone'})` : ''}
                                    value={selectedCustomer}
                                    onChange={(_, newValue) => setSelectedCustomer(newValue)}
                                    renderInput={(params) => (
                                        <MuiTextField
                                            {...params}
                                            placeholder="Select Customer"
                                            variant="outlined"
                                            fullWidth
                                            sx={{ '& .MuiOutlinedInput-root': { borderRadius: '12px' } }}
                                        />
                                    )}
                                />
                            </div>

                            <div className="form-group" style={{ marginTop: '20px' }}>
                                <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Add Products to Sale</InputLabel>
                                <Autocomplete
                                    options={products || []}
                                    getOptionLabel={(option) => option?.name ? `${option.name} - $${option.price?.toFixed(2)} (${option.stock} in stock)` : ''}
                                    onChange={(_, newValue) => {
                                        if (newValue) {
                                            addToCart(newValue)
                                        }
                                    }}
                                    renderInput={(params) => (
                                        <MuiTextField
                                            {...params}
                                            placeholder="Search Products..."
                                            variant="outlined"
                                            fullWidth
                                            sx={{ '& .MuiOutlinedInput-root': { borderRadius: '12px' } }}
                                        />
                                    )}
                                    clearOnBlur
                                    handleHomeEndKeys
                                />
                            </div>

                            <div className="form-group" style={{ marginTop: '20px' }}>
                                <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Payment Method</InputLabel>
                                <FormControl fullWidth>
                                    <Select
                                        value={paymentMethod}
                                        onChange={(e) => setPaymentMethod(e.target.value)}
                                        sx={{ borderRadius: '12px' }}
                                    >
                                        <MenuItem value="cash">Cash</MenuItem>
                                        <MenuItem value="card">Card</MenuItem>
                                    </Select>
                                </FormControl>
                            </div>
                        </div>

                        <div className="new-sale-cart">
                            <h3 className="cart-title">Order Items</h3>
                            <div className="cart-list">
                                {cart.length === 0 ? (
                                    <div className="empty-cart">No items added yet.</div>
                                ) : (
                                    <table className="cart-table">
                                        <thead>
                                            <tr>
                                                <th>Product</th>
                                                <th>Qty</th>
                                                <th>Price</th>
                                                <th></th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {cart.map((item) => (
                                                <tr key={item.id}>
                                                    <td>{item.name}</td>
                                                    <td>
                                                        <input
                                                            type="number"
                                                            className="qty-input"
                                                            value={item.qty}
                                                            onChange={(e) => updateCartQty(item.id, parseInt(e.target.value) || 1)}
                                                            min="1"
                                                        />
                                                    </td>
                                                    <td>${(item.price * item.qty).toFixed(2)}</td>
                                                    <td>
                                                        <button className="remove-item" onClick={() => removeFromCart(item.id)}>
                                                            <DeleteOutlineIcon sx={{ fontSize: 18 }} />
                                                        </button>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                )}
                            </div>
                            <div className="cart-footer">
                                <div className="cart-total">
                                    <span>Total Amount:</span>
                                    <span>${totalAmount.toFixed(2)}</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="form-actions">
                        <Button variant="outlined" onClick={() => setIsModalOpen(false)} disabled={isSubmitting}>
                            Cancel
                        </Button>
                        <Button
                            variant="filled"
                            onClick={handleCreateSale}
                            disabled={isSubmitting || cart.length === 0}
                            sx={{ minWidth: '150px' }}
                        >
                            {isSubmitting ? 'Recording...' : 'Record Sale'}
                        </Button>
                    </div>
                </div>
            </Modal>

            {/* View Invoice Modal */}
            <InvoiceModal
                isOpen={isInvoiceModalOpen}
                onClose={() => {
                    setIsInvoiceModalOpen(false)
                    setSelectedSale(null)
                }}
                sale={selectedSale}
                businessName={user?.businessName}
            />
        </OwnerLayout>
    )
}

import { useState, useMemo } from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import DataTable from '../../../common/component/DataTable/DataTable'
import TextField from '../../../common/component/TextField/TextField'
import Button from '../../../common/component/Button/Button'
import Modal from '../../../common/component/Modal/Modal'
import SearchIcon from '@mui/icons-material/Search'
import AddIcon from '@mui/icons-material/Add'
import EditOutlinedIcon from '@mui/icons-material/EditOutlined'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'
import EmailOutlinedIcon from '@mui/icons-material/EmailOutlined'
import PhoneOutlinedIcon from '@mui/icons-material/PhoneOutlined'
import { useSuppliers } from '../../../context/SupplierContext'
import './BusinessOwnerSupplier.css'

export default function BusinessOwnerSupplier() {
    const { suppliers, loading, addSupplier, updateSupplier, deleteSupplier } = useSuppliers()
    const [searchQuery, setSearchQuery] = useState('')
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [editingSupplier, setEditingSupplier] = useState(null)
    const [isSubmitting, setIsSubmitting] = useState(false)

    // Form State
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        phone: '',
        address: ''
    })

    const filteredSuppliers = useMemo(() => {
        return suppliers.filter(s =>
            s.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.phone?.includes(searchQuery)
        )
    }, [suppliers, searchQuery])

    const handleInputChange = (e) => {
        const { name, value } = e.target
        setFormData(prev => ({ ...prev, [name]: value }))
    }

    const handleOpenAddModal = () => {
        setEditingSupplier(null)
        setFormData({ name: '', email: '', phone: '', address: '' })
        setIsModalOpen(true)
    }

    const handleOpenEditModal = (supplier) => {
        setEditingSupplier(supplier)
        setFormData({
            name: supplier.name || '',
            email: supplier.email || '',
            phone: supplier.phone || '',
            address: supplier.address || ''
        })
        setIsModalOpen(true)
    }

    const handleDeleteSupplier = async (id) => {
        if (window.confirm('Are you sure you want to delete this supplier?')) {
            await deleteSupplier(id)
        }
    }

    const handleSubmit = async (e) => {
        e.preventDefault()
        setIsSubmitting(true)

        let result;
        if (editingSupplier) {
            result = await updateSupplier(editingSupplier.supplierId, formData)
        } else {
            result = await addSupplier(formData)
        }

        if (result.success) {
            setIsModalOpen(false)
        } else {
            alert('Failed to save supplier. Please try again.')
        }
        setIsSubmitting(false)
    }

    const columns = useMemo(() => [
        {
            key: 'name',
            label: 'Company Name',
            render: (val) => <span style={{ fontWeight: 600 }}>{val}</span>
        },
        {
            key: 'email',
            label: 'Email',
            render: (val) => (
                <div className="contact-item">
                    <EmailOutlinedIcon sx={{ fontSize: 18, marginRight: 1, color: '#666' }} /> {val}
                </div>
            )
        },
        {
            key: 'phone',
            label: 'Phone',
            render: (val) => (
                <div className="contact-item">
                    <PhoneOutlinedIcon sx={{ fontSize: 18, marginRight: 1, color: '#666' }} /> {val}
                </div>
            )
        },
        {
            key: 'address',
            label: 'Address',
            render: (val) => <div className="address-cell">{val}</div>
        },
        {
            key: 'actions',
            label: 'Actions',
            render: (_, row) => (
                <div className="action-buttons">
                    <button
                        className="action-btn action-btn--edit"
                        onClick={() => handleOpenEditModal(row)}
                    >
                        <EditOutlinedIcon />
                    </button>
                    <button
                        className="action-btn action-btn--delete"
                        onClick={() => handleDeleteSupplier(row.supplierId)}
                    >
                        <DeleteOutlineIcon />
                    </button>
                </div>
            )
        }
    ], [])

    return (
        <OwnerLayout breadcrumb="Suppliers">
            <div className="suppliers-page">
                <div className="suppliers-section">
                    <div className="suppliers-header">
                        <h2 className="suppliers-title">Supplier Management</h2>
                        <Button
                            variant="filled"
                            startIcon={<AddIcon />}
                            onClick={handleOpenAddModal}
                            sx={{ backgroundColor: '#000', borderRadius: '8px' }}
                        >
                            Add Supplier
                        </Button>
                    </div>

                    <div className="suppliers-toolbar">
                        <TextField
                            placeholder="Search suppliers..."
                            icon={<SearchIcon />}
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            fullWidth
                        />
                    </div>

                    <div className="suppliers-table-container">
                        <DataTable
                            columns={columns}
                            data={filteredSuppliers}
                            isLoading={loading && suppliers.length === 0}
                        />
                    </div>
                </div>
            </div>

            {/* Add/Edit Supplier Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingSupplier ? "Edit Supplier" : "Add New Supplier"}
            >
                <form className="supplier-form" onSubmit={handleSubmit}>
                    <div className="form-grid">
                        <TextField
                            name="name"
                            label="Company Name"
                            placeholder="Enter Company Name"
                            value={formData.name}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                        <TextField
                            name="email"
                            label="Email Address"
                            type="email"
                            placeholder="Enter Email Address"
                            value={formData.email}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                        <TextField
                            name="phone"
                            label="Phone Number"
                            placeholder="Enter Phone Number"
                            value={formData.phone}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                        <TextField
                            name="address"
                            label="Address"
                            placeholder="Enter Address"
                            value={formData.address}
                            onChange={handleInputChange}
                            required
                            fullWidth
                        />
                    </div>
                    <div className="form-actions">
                        <Button variant="outlined" onClick={() => setIsModalOpen(false)} disabled={isSubmitting}>
                            Cancel
                        </Button>
                        <Button type="submit" variant="filled" disabled={isSubmitting}>
                            {isSubmitting ? 'Saving...' : (editingSupplier ? 'Update Supplier' : 'Add Supplier')}
                        </Button>
                    </div>
                </form>
            </Modal>
        </OwnerLayout>
    )
}

import { useState, useMemo } from 'react'
import OwnerLayout from '../../../common/component/OwnerLayout/OwnerLayout'
import DataTable from '../../../common/component/DataTable/DataTable'
import Button from '../../../common/component/Button/Button'
import Modal from '../../../common/component/Modal/Modal'
import AddIcon from '@mui/icons-material/Add'
import EditOutlinedIcon from '@mui/icons-material/EditOutlined'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'
import MuiTextField from '@mui/material/TextField'
import MenuItem from '@mui/material/MenuItem'
import Select from '@mui/material/Select'
import FormControl from '@mui/material/FormControl'
import InputLabel from '@mui/material/InputLabel'
import TrendingUpIcon from '@mui/icons-material/TrendingUp'
import TrendingDownIcon from '@mui/icons-material/TrendingDown'
import { useTransactions } from '../../../context/TransactionContext'
import './BusinessOwnerTransaction.css'

export default function BusinessOwnerTransaction() {
    const { transactions, loading, addTransaction, editTransaction, deleteTransaction } = useTransactions()

    const [isModalOpen, setIsModalOpen] = useState(false)
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [editingTransaction, setEditingTransaction] = useState(null)

    // Form State
    const [formData, setFormData] = useState({
        date: new Date().toISOString().split('T')[0],
        type: 'expense',
        category: 'Other',
        description: '',
        amount: ''
    })

    const categories = ['Marketing', 'Suppliers', 'Inventory', 'Utilities', 'Rent', 'Payroll', 'Other', 'Sales', 'Services']

    // Calculate totals
    const totalIncome = transactions
        .filter(t => t.type === 'income')
        .reduce((sum, t) => sum + Number(t.amount), 0)

    const totalExpenses = transactions
        .filter(t => t.type === 'expense')
        .reduce((sum, t) => sum + Number(t.amount), 0)

    const handleOpenModal = (transaction = null) => {
        if (transaction) {
            setEditingTransaction(transaction)
            setFormData({
                date: transaction.date ? transaction.date.split('T')[0] : '',
                type: transaction.type || 'expense',
                category: transaction.category || 'Other',
                description: transaction.description || '',
                amount: transaction.amount || ''
            })
        } else {
            setEditingTransaction(null)
            setFormData({
                date: new Date().toISOString().split('T')[0],
                type: 'expense',
                category: 'Other',
                description: '',
                amount: ''
            })
        }
        setIsModalOpen(true)
    }

    const handleDelete = async (transaction) => {
        if (window.confirm('Are you sure you want to delete this transaction?')) {
            const id = transaction.transactionId || transaction.id
            const res = await deleteTransaction(id)
            if (!res.success) {
                alert('Error: ' + res.error)
            }
        }
    }

    const handleSubmit = async () => {
        if (!formData.description || !formData.amount || !formData.category) {
            alert('Please fill all required fields')
            return
        }

        setIsSubmitting(true)
        try {
            const payload = {
                ...formData,
                amount: Number(formData.amount)
            }

            let result
            if (editingTransaction) {
                const id = editingTransaction.transactionId || editingTransaction.id
                result = await editTransaction(id, payload)
            } else {
                result = await addTransaction(payload)
            }

            if (result.success) {
                setIsModalOpen(false)
            } else {
                alert('Error processing transaction: ' + result.error)
            }
        } catch (err) {
            console.error(err)
            alert('An unexpected error occurred.')
        } finally {
            setIsSubmitting(false)
        }
    }

    const columns = useMemo(() => [
        {
            key: 'date',
            label: 'Date',
            render: (val) => <span>{val ? new Date(val).toLocaleDateString() : 'N/A'}</span>
        },
        {
            key: 'type',
            label: 'Type',
            render: (val) => (
                <span className={`type-badge type-badge--${val}`}>
                    {val === 'income' ? <TrendingUpIcon sx={{ fontSize: 16 }} /> : <TrendingDownIcon sx={{ fontSize: 16 }} />}
                    {val}
                </span>
            )
        },
        {
            key: 'category',
            label: 'Category',
            render: (val) => <span>{val}</span>
        },
        {
            key: 'description',
            label: 'Description',
            render: (val) => <span>{val}</span>
        },
        {
            key: 'amount',
            label: 'Amount',
            render: (val, row) => (
                <span className={`amount-cell amount-cell--${row.type}`}>
                    {row.type === 'income' ? '+' : '-'}${Number(val).toFixed(2)}
                </span>
            )
        },
        {
            key: 'actions',
            label: 'Actions',
            render: (_, row) => (
                <div className="action-buttons">
                    <button
                        className="action-btn action-btn--edit"
                        title="Edit Transaction"
                        onClick={() => handleOpenModal(row)}
                    >
                        <EditOutlinedIcon sx={{ fontSize: 20 }} />
                    </button>
                    <button
                        className="action-btn action-btn--delete"
                        title="Delete Transaction"
                        onClick={() => handleDelete(row)}
                        style={{ color: '#e53e3e', marginLeft: '8px' }}
                    >
                        <DeleteOutlineIcon sx={{ fontSize: 20 }} />
                    </button>
                </div>
            )
        }
    ], [])

    return (
        <OwnerLayout breadcrumb="Transactions">
            <div className="transactions-page">
                {/* Summary Cards */}
                <div className="summary-cards">
                    <div className="summary-card">
                        <div className="summary-card-title">Total Income</div>
                        <div className="summary-card-value income-value">
                            ${totalIncome.toFixed(2)}
                        </div>
                    </div>
                    <div className="summary-card">
                        <div className="summary-card-title">Total Expenses</div>
                        <div className="summary-card-value expense-value">
                            ${totalExpenses.toFixed(2)}
                        </div>
                    </div>
                </div>

                <div className="transactions-section">
                    <div className="transactions-header">
                        <h2 className="transactions-title">Daily Transactions</h2>
                        <Button
                            variant="filled"
                            startIcon={<AddIcon />}
                            onClick={() => handleOpenModal()}
                            sx={{ backgroundColor: '#000', borderRadius: '8px' }}
                        >
                            Add Transaction
                        </Button>
                    </div>

                    <div className="transactions-table-container">
                        <DataTable
                            columns={columns}
                            data={transactions}
                            isLoading={loading && transactions.length === 0}
                        />
                    </div>
                </div>
            </div>

            {/* Transaction Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingTransaction ? "Edit Transaction" : "Log a Transaction"}
            >
                <div className="transaction-form-container">
                    <div className="form-group">
                        <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Date</InputLabel>
                        <MuiTextField
                            type="date"
                            value={formData.date}
                            onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                            variant="outlined"
                            fullWidth
                            sx={{ '& .MuiOutlinedInput-root': { borderRadius: '12px' } }}
                        />
                    </div>

                    <div className="form-row" style={{ display: 'flex', gap: '16px', marginTop: '20px' }}>
                        <div className="form-group" style={{ flex: 1 }}>
                            <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Type</InputLabel>
                            <FormControl fullWidth>
                                <Select
                                    value={formData.type}
                                    onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                                    sx={{ borderRadius: '12px' }}
                                >
                                    <MenuItem value="income">Income</MenuItem>
                                    <MenuItem value="expense">Expense</MenuItem>
                                </Select>
                            </FormControl>
                        </div>

                        <div className="form-group" style={{ flex: 1 }}>
                            <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Category</InputLabel>
                            <FormControl fullWidth>
                                <Select
                                    value={formData.category}
                                    onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                    sx={{ borderRadius: '12px' }}
                                >
                                    {categories.map((cat) => (
                                        <MenuItem key={cat} value={cat}>{cat}</MenuItem>
                                    ))}
                                </Select>
                            </FormControl>
                        </div>
                    </div>

                    <div className="form-group" style={{ marginTop: '20px' }}>
                        <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Description</InputLabel>
                        <MuiTextField
                            value={formData.description}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                            placeholder="Enter description..."
                            variant="outlined"
                            fullWidth
                            sx={{ '& .MuiOutlinedInput-root': { borderRadius: '12px' } }}
                        />
                    </div>

                    <div className="form-group" style={{ marginTop: '20px' }}>
                        <InputLabel sx={{ mb: 1, fontWeight: 600, color: '#2d3748' }}>Amount</InputLabel>
                        <MuiTextField
                            type="number"
                            value={formData.amount}
                            onChange={(e) => setFormData({ ...formData, amount: e.target.value })}
                            placeholder="0.00"
                            variant="outlined"
                            fullWidth
                            sx={{ '& .MuiOutlinedInput-root': { borderRadius: '12px' } }}
                        />
                    </div>

                    <div className="form-actions" style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px', marginTop: '30px' }}>
                        <Button variant="outlined" onClick={() => setIsModalOpen(false)} disabled={isSubmitting}>
                            Cancel
                        </Button>
                        <Button
                            variant="filled"
                            onClick={handleSubmit}
                            disabled={isSubmitting}
                            sx={{ minWidth: '150px' }}
                        >
                            {isSubmitting ? 'Saving...' : 'Save'}
                        </Button>
                    </div>
                </div>
            </Modal>
        </OwnerLayout>
    )
}
